В events.jsonl каждая строка — JSON с req,event,ts_ms. event: start/end.
Собери latency_report.json со структурой:
  - durations_ms: объект req->duration_ms для запросов, у которых есть и start, и end;
  - slow_requests: список из 2 req с максимальной duration_ms (по убыванию);
  - incomplete_count: сколько req не имеют пары start+end.
Если у req несколько событий одного типа, бери первую корректную пару start->end.

args.content:
import json
from collections import defaultdict

def process_events(input_path, output_path):
    start_times = {}
    end_times = {}
    durations_ms = {}
    incomplete_reqs = set()

    with open(input_path, 'r', encoding='utf-8') as f:
        for line in f:
            if not line.strip():
                continue
            record = json.loads(line)
            req_id = record['req']
            event_type = record['event']
            ts = record['ts_ms']

            # Пропускаем дубликаты: берём только первую корректную пару для каждого типа события
            if event_type == 'start':
                if req_id not in start_times:
                    start_times[req_id] = ts
            elif event_type == 'end':
                if req_id not in end_times:
                    end_times[req_id] = ts

    all_reqs = set(start_times.keys()) | set(end_times.keys())

    # Считаем полные пары и длительности
    for req_id in all_reqs:
        has_start = req_id in start_times
        has_end = req_id in end_times
        if has_start and has_end:
            duration = end_times[req_id] - start_times[req_id]
            durations_ms[req_id] = duration
        else:
            incomplete_reqs.add(req_id)

    # Топ-2 самых медленных запроса по убыванию
    slow_requests = sorted(durations_ms.items(), key=lambda x: x[1], reverse=True)[:2]
    slow_req_list = [req for req, _ in slow_requests]

    report = {
        "durations_ms": durations_ms,
        "slow_requests": slow_req_list,
        "incomplete_count": len(incomplete_reqs)
    }

    with open(output_path, 'w', encoding='utf-8') as out_f:
        json.dump(report, out_f, ensure_ascii=False, indent=2)

if __name__ == "__main__":
    process_events('events.jsonl', 'latency_report.json')

